import { Component } from '@angular/core';
import { FormBuilder, FormGroup, ReactiveFormsModule, Validators } from '@angular/forms';

@Component({
  selector: 'app-root',
  standalone: true,
  imports: [ReactiveFormsModule],
  template: `
    <main class="app">
      <section class="card" [formGroup]="form">
        <header class="header">
          <h1>Multi-step Signup</h1>
          <p class="subtitle">Step {{ currentStep + 1 }} of 3</p>
        </header>

        <section class="steps">
          @switch (currentStep) {
          <!-- Step 1: Basic info -->
            @case (0) {
              <div formGroupName="basic" class="step">
            <h2 class="step-title">Basic info</h2>
            <label class="field">
              <span>Name</span>
              <input type="text" formControlName="name" placeholder="Jane Doe" />
              @if (basicGroup.get('name')?.touched && basicGroup.get('name')?.invalid) {
                <small class="error">
                Name is required.
                </small>
              }
            </label>

            <label class="field">
              <span>Email</span>
              <input type="email" formControlName="email" placeholder="jane@example.com" />
              @if (basicGroup.get('email')?.touched && basicGroup.get('email')?.invalid) {
                <small class="error">
                Please enter a valid email.
                </small>
              }
            </label>
              </div>
            }

          <!-- Step 2: Address info -->
            @case (1) {
              <div formGroupName="address" class="step">
            <h2 class="step-title">Address</h2>
            <label class="field">
              <span>Street</span>
              <input type="text" formControlName="street" placeholder="123 Main St" />
              @if (addressGroup.get('street')?.touched && addressGroup.get('street')?.invalid) {
                <small class="error">
                Street is required.
                </small>
              }
            </label>

            <label class="field">
              <span>City</span>
              <input type="text" formControlName="city" placeholder="Istanbul" />
              @if (addressGroup.get('city')?.touched && addressGroup.get('city')?.invalid) {
                <small class="error">
                City is required.
                </small>
              }
            </label>

            <label class="field">
              <span>Country</span>
              <input type="text" formControlName="country" placeholder="Türkiye" />
              @if (addressGroup.get('country')?.touched && addressGroup.get('country')?.invalid) {
                <small class="error">
                Country is required.
                </small>
              }
            </label>

            <label class="field">
              <span>Postal code (optional)</span>
              <input type="text" formControlName="postalCode" placeholder="34000" />
            </label>
              </div>
            }

          <!-- Step 3: Summary -->
            @case (2) {
              <div class="step">
            <h2 class="step-title">Summary</h2>
            <div class="summary">
              <h3>Basic info</h3>
              <p><strong>Name:</strong> {{ basicGroup.get('name')?.value }}</p>
              <p><strong>Email:</strong> {{ basicGroup.get('email')?.value }}</p>

              <h3>Address</h3>
              <p><strong>Street:</strong> {{ addressGroup.get('street')?.value }}</p>
              <p><strong>City:</strong> {{ addressGroup.get('city')?.value }}</p>
              <p><strong>Country:</strong> {{ addressGroup.get('country')?.value }}</p>
              <p><strong>Postal code:</strong> {{ addressGroup.get('postalCode')?.value || '—' }}</p>
            </div>
              </div>
            }
          }
        </section>

        <footer class="actions">
          <button type="button" class="ghost" (click)="prev()" [disabled]="isFirstStep">
            Back
          </button>

          @if (!isLastStep) {
            <button
            type="button"
            (click)="next()"
            [disabled]="!canGoNext"
          >
            Next
            </button>
          }

          @if (isLastStep) {
            <button
            type="button"
            class="primary"
            (click)="submit()"
          >
            Submit
            </button>
          }
        </footer>
      </section>
    </main>
  `,
  styles: [
    `.app{min-height:100vh;display:grid;place-items:center;background:#020617;color:#e5e7eb;padding:24px;}`,
    `.card{width:100%;max-width:520px;background:#020617;border-radius:16px;border:1px solid #1f2937;padding:20px 20px 16px;display:grid;gap:16px;}`,
    `.header h1{margin:0;font-size:20px;font-weight:700;}`,
    `.subtitle{margin:4px 0 0;font-size:13px;color:#9ca3af;}`,
    `.steps{min-height:260px;}`,
    `.step{display:grid;gap:12px;}`,
    `.step-title{margin:0 0 4px;font-size:16px;font-weight:600;}`,
    `.field{display:grid;gap:4px;font-size:13px;}`,
    `.field span{color:#e5e7eb;}`,
    `.field input{border-radius:10px;border:1px solid #374151;background:#020617;padding:8px 10px;color:#e5e7eb;font-size:14px;}`,
    `.field input:focus{outline:none;border-color:#a3e635;}`,
    `.error{font-size:11px;color:#f97316;}`,
    `.summary{display:grid;gap:4px;font-size:14px;}`,
    `.summary h3{margin:8px 0 2px;font-size:14px;font-weight:600;color:#e5e7eb;}`,
    `.actions{display:flex;justify-content:space-between;gap:8px;margin-top:4px;}`,
    `.actions button{border-radius:999px;border:1px solid #374151;background:#020617;color:#e5e7eb;padding:8px 16px;font-size:14px;font-weight:600;cursor:pointer;}`,
    `.actions button.primary{background:#a3e635;color:#020617;border-color:#a3e635;}`,
    `.actions button[disabled]{opacity:.5;cursor:not-allowed;}`,
    `.actions button.ghost{background:transparent;}`
  ]
})
export class AppComponent {
  readonly lastStepIndex = 2;
  currentStep = 0;

  constructor(private fb: FormBuilder) {}

  form: FormGroup = this.fb.group({
    basic: this.fb.group({
      name: ['', Validators.required],
      email: ['', [Validators.required, Validators.email]]
    }),
    address: this.fb.group({
      street: ['', Validators.required],
      city: ['', Validators.required],
      country: ['', Validators.required],
      postalCode: ['']
    })
  });

  get basicGroup(): FormGroup {
    return this.form.get('basic') as FormGroup;
  }

  get addressGroup(): FormGroup {
    return this.form.get('address') as FormGroup;
  }

  get isFirstStep(): boolean {
    return this.currentStep === 0;
  }

  get isLastStep(): boolean {
    return this.currentStep === this.lastStepIndex;
  }

  get canGoNext(): boolean {
    if (this.currentStep === 0) {
      return this.basicGroup.valid;
    }
    if (this.currentStep === 1) {
      return this.addressGroup.valid;
    }
    return false;
  }

  private currentGroup(): FormGroup {
    if (this.currentStep === 0) return this.basicGroup;
    if (this.currentStep === 1) return this.addressGroup;
    return this.form;
  }

  next(): void {
    const group = this.currentGroup();
    group.markAllAsTouched();
    if (group.invalid) {
      return;
    }
    if (!this.isLastStep) {
      this.currentStep++;
    }
  }

  prev(): void {
    if (!this.isFirstStep) {
      this.currentStep--;
    }
  }

  submit(): void {
    this.form.markAllAsTouched();
    if (this.form.invalid) {
      return;
    }
    console.log('Signup submitted', this.form.value);
  }
}
